script:
(function() {
  // Dim the screen
  let dimOverlay = document.getElementById('gemma-dim-overlay');
  if (!dimOverlay) {
    dimOverlay = document.createElement('div');
    dimOverlay.id = 'gemma-dim-overlay';
    dimOverlay.style.position = 'fixed';
    dimOverlay.style.top = '0';
    dimOverlay.style.left = '0';
    dimOverlay.style.width = '100vw';
    dimOverlay.style.height = '100vh';
    dimOverlay.style.background = 'rgba(0,0,0,0.8)';
    dimOverlay.style.zIndex = '100000';
    dimOverlay.style.pointerEvents = 'none';
    document.body.appendChild(dimOverlay);
  } else {
    dimOverlay.style.display = 'block';
  }
  // Fireworks
  let canvas = document.getElementById('gemma-fireworks-canvas');
  if (!canvas) {
    canvas = document.createElement('canvas');
    canvas.id = 'gemma-fireworks-canvas';
    canvas.style.position = 'fixed';
    canvas.style.top = '0';
    canvas.style.left = '0';
    canvas.style.width = '100vw';
    canvas.style.height = '100vh';
    canvas.style.pointerEvents = 'none';
    canvas.style.zIndex = '100001';
    document.body.appendChild(canvas);
  } else {
    canvas.style.display = 'block';
  }
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  // Fireworks animation
  // More explosive fireworks effect
  const ctx = canvas.getContext('2d');
  let particles = [];
  function randomColor() {
    const colors = ['#ff5252','#ffd700','#00e676','#40c4ff','#e040fb','#ffab40','#fff'];
    return colors[Math.floor(Math.random()*colors.length)];
  }
  function createFirework() {
    const x = Math.random() * canvas.width * 0.8 + canvas.width * 0.1;
    const y = Math.random() * canvas.height * 0.5 + canvas.height * 0.1;
    const color = randomColor();
    const count = Math.floor(Math.random() * 24) + 48; // 48-72 particles
    for (let i = 0; i < count; i++) {
      const angle = (Math.PI * 2 * i) / count;
      const speed = Math.random() * 7 + 4; // faster
      particles.push({
        x, y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        alpha: 1,
        color,
        size: Math.random() * 2 + 2 // larger
      });
    }
  }
  let frame = 0;
  let fadeFrame = 0;
  let fading = false;
  function animate() {
    ctx.clearRect(0,0,canvas.width,canvas.height);
    particles.forEach(p => {
      ctx.globalAlpha = p.alpha;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.size, 0, Math.PI*2);
      ctx.fillStyle = p.color;
      ctx.shadowColor = p.color;
      ctx.shadowBlur = 16;
      ctx.fill();
      ctx.shadowBlur = 0;
    });
    ctx.globalAlpha = 1;
    particles.forEach(p => {
      p.x += p.vx;
      p.y += p.vy;
      p.vx *= 0.94; // slower fade
      p.vy *= 0.94;
      p.alpha -= 0.009; // slower fade
    });
    particles = particles.filter(p => p.alpha > 0.04);
    if (frame % 18 === 0 && !fading) createFirework(); // more frequent
    frame++;
    if (frame < 260) { // longer duration
      requestAnimationFrame(animate);
    } else if (!fading) {
      fading = true;
      fadeFrame = 0;
      requestAnimationFrame(fadeOut);
      requestAnimationFrame(animate); // keep animating
    } else if (fading && fadeFrame < 40) {
      requestAnimationFrame(animate);
    }
  }
  function fadeOut() {
    fadeFrame++;
    const fadeDuration = 40;
    const opacity = Math.max(0, 1 - fadeFrame / fadeDuration);
    if (dimOverlay) dimOverlay.style.opacity = opacity;
    if (canvas) canvas.style.opacity = opacity;
    if (fadeFrame < fadeDuration) {
      requestAnimationFrame(fadeOut);
    } else {
      if (dimOverlay) {
        dimOverlay.style.display = 'none';
        dimOverlay.style.opacity = 1;
      }
      if (canvas) {
        canvas.style.display = 'none';
        canvas.style.opacity = 1;
      }
    }
  }
  createFirework();
  animate();
})();
